#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.bloodAndGore)]
    public class BloodAndGoreOptionToggle : OptionToggleDefinition
    {
        public BloodAndGoreOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return context is not IOptionContextLevel;
        }
        public override bool GetValue(IOptionContext context)
        {
            return context.TryGetCachedOptionBool(LogicOptionItemID.showHotkeys, out var value) ? value : Global.Options.HasBloodAndGore();
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            context.CacheOptionBool(LogicOptionItemID.bloodAndGore, value);
            context.SetNeedReload();
        }
    }
}
